@pytest.mark.parametrize("d_size, b_size, problem_name, tours", TEST_CASES)
def test_refSetFixedDiversity_set(d_size, b_size, problem_name, tours):
    problem_path = f"./src/ScatterSearchTSP/tsp_instances/{problem_name}"
    problem = tsplib.load(problem_path)
    ref = refSet.RefSetFixedDiversity(d_size=d_size, b_size=b_size, 
                                      fitness_fn=lambda t: utils.trace_tour(problem, t), distance_fn=utils.permutation_difference)
    res = ref.set(tours)
    assert res == d_size + b_size






